module.exports=async({github,context,core})=>{const fs=require('node:fs'),path='lighthouse-comment.md';if(!fs.existsSync(path)){core.warning('Lighthouse markdown was not generated');return}const body=fs.readFileSync(path,'utf8'),marker='<!-- robys-lighthouse-report -->';try{const comments=await github.paginate(github.rest.issues.listComments,{owner:context.repo.owner,repo:context.repo.repo,issue_number:context.issue.number,per_page:100}),existing=comments.find(c=>c.user?.type==='Bot'&&c.body?.includes(marker));if(existing)await github.rest.issues.updateComment({owner:context.repo.owner,repo:context.repo.repo,comment_id:existing.id,body});else await github.rest.issues.createComment({owner:context.repo.owner,repo:context.repo.repo,issue_number:context.issue.number,body})}catch(error){core.warning(`Unable to publish Lighthouse PR comment: ${error.message}`)}};
